// Coordinator — Phase 3 task 3.2
// Per design plan §2.2. See P-3 in .claude/memory/pitfalls.md — n8n 2.17.7
// Code-node sandbox blocks require('crypto') AND Web Crypto global `crypto`.
// Math.random-based UUID v4 is acceptable here (I-2 scoped to RFD only).

// ---- filename-regex source_type classifier (design plan §2.3) ----
const CLASSIFIER = [
  { rx: /\b(s-?1|10-?k|10-?q|8-?k|20-?f|prospectus)\b/i, source_type: 'regulatory_filing',  human: 'S-1 Filing' },
  { rx: /\b(press[\s\-_]release|announce(?:ment)?|newswire)\b/i, source_type: 'press_release',     human: 'Press Release' },
  { rx: /\b(teardown|analysis|report|breakdown|case[\s\-_]study)\b/i, source_type: 'analyst_report',    human: 'Analyst Report' },
  { rx: /\b(transcript|call|interview)\b/i,                source_type: 'expert_transcript', human: 'Expert Transcript' },
  { rx: /\b(deck|presentation|pitch|slide)\b/i,            source_type: 'management_deck',   human: 'Management Deck' },
];
function classifyFilename(filename) {
  for (const c of CLASSIFIER) {
    if (c.rx.test(filename)) return { source_type: c.source_type, human: c.human };
  }
  return { source_type: 'regulatory_filing', human: 'S-1 Filing' };
}

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

const item = $input.item.json;

const companyName = item['Company Name'] || item.company_name || 'Unknown Company';
const dealId = companyName.toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');
const runId = uuidv4();
const timestampStarted = new Date().toISOString();

// Form Trigger emits file metadata on item.Documents (matches form label).
// Actual binaries are on $input.item.binary (filesystem-stored in 2.17.7).
const uploadedDocs = Array.isArray(item.Documents) ? item.Documents : [];

const humanCounts = {};
const documents = uploadedDocs.map((d, idx) => {
  const filename = d.filename || `file-${idx}.pdf`;
  const { source_type, human } = classifyFilename(filename);
  humanCounts[human] = (humanCounts[human] || 0) + 1;
  const suffix = humanCounts[human] > 1 ? ` (#${humanCounts[human]})` : '';
  return {
    file_id: uuidv4(),
    filename,
    source_name: `${companyName} ${human}${suffix}`,
    source_type,
    mime: d.mimetype || 'application/pdf',
    bytes: d.size || 0,
  };
});

const source_manifest = documents.map(d => d.source_name);

if (documents.length < 2) throw new Error(`Need at least 2 documents; received ${documents.length}.`);
if (documents.length > 4) throw new Error(`Maximum 4 documents supported; received ${documents.length}.`);

return {
  json: {
    run_id: runId,
    deal_id: dealId,
    company_name: companyName,
    timestamp_started: timestampStarted,
    documents,
    source_manifest,
  },
  binary: $input.item.binary,
};

// Split per-document — Phase 3 task 3.3a
// Takes the Coordinator's single item (with N documents + N binaries)
// and emits N items, each carrying:
//   - json: run metadata + this document's metadata on `document` field
//   - binary: { data: <this document's binary> }
//
// Binary key discovery: n8n's Form Trigger multi-file output stores each
// upload under a binary key. The key format varies by n8n version; we
// match binary entries to documents by filename (most robust), with an
// index-based fallback if the binary object lacks fileName metadata.

const items = $input.all();
if (items.length !== 1) {
  throw new Error(`Expected 1 input item from Coordinator, got ${items.length}`);
}
const item = items[0];
const meta = item.json;
const binary = item.binary || {};
const binaryKeys = Object.keys(binary);

if (binaryKeys.length !== meta.documents.length) {
  // Not fatal; log for diagnosis and continue with whatever we have.
  console.log(`WARN: documents=${meta.documents.length} but binaryKeys=${binaryKeys.length}`);
}

// Build a lookup: filename → binary entry. Fallback to index order.
function findBinaryForDoc(doc, idx) {
  // Try fileName match first (most n8n versions set this).
  for (const key of binaryKeys) {
    const b = binary[key];
    if (b && (b.fileName === doc.filename || b.fileName?.toLowerCase() === doc.filename.toLowerCase())) {
      return { key, entry: b };
    }
  }
  // Fallback: index-order assumption (Coordinator iterated same order).
  const fallbackKey = binaryKeys[idx];
  if (fallbackKey) return { key: fallbackKey, entry: binary[fallbackKey] };
  return null;
}

const results = meta.documents.map((doc, idx) => {
  const match = findBinaryForDoc(doc, idx);
  if (!match) {
    throw new Error(`No binary found for document: ${doc.filename}`);
  }
  return {
    json: {
      run_id: meta.run_id,
      deal_id: meta.deal_id,
      company_name: meta.company_name,
      timestamp_started: meta.timestamp_started,
      source_manifest: meta.source_manifest,
      document: doc, // {file_id, filename, source_name, source_type, mime, bytes}
    },
    // Copy the matched binary onto a stable property name 'data' so
    // downstream Extract from File can reference it predictably.
    binary: { data: match.entry },
  };
});

return results;

// Text Chunker — Phase 3 task 3.3b
// ⚠ Extract from File (upstream) REPLACES $json with {text, numpages,
// info, version}, dropping the document metadata (file_id, source_name,
// etc.) and run-level metadata (run_id, deal_id, ...). See P-4 in
// pitfalls.md — same anti-pattern as HTTP Request, different node class.
// Recovery: reach back to Split Per-Document via $('...').all(),
// matching by position (n8n preserves item order through nodes).
//
// Character-based chunking: n8n Code sandbox has no tokenizer access
// (tiktoken etc. would need require); approximate 1 token ≈ 4 chars for
// English regulatory prose. 1000 tokens ≈ 4000 chars, 100 overlap ≈ 400.

const CHUNK_CHARS = 4000;
const OVERLAP_CHARS = 400;
const CHARS_PER_PAGE = 2000;

const items = $input.all();                         // from Extract from File
const splitItems = $('Split Per-Document').all();   // before Extract from File — has document meta

if (items.length !== splitItems.length) {
  console.log(`WARN: Chunker input count (${items.length}) != Split Per-Document count (${splitItems.length}); ordering match may be off.`);
}

const chunks = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const splitItem = splitItems[i];
  if (!splitItem) {
    console.log(`WARN: no matching Split item at position ${i}; skipping.`);
    continue;
  }

  const text = typeof item.json.text === 'string' ? item.json.text : '';
  if (text.length === 0) continue; // skip empty docs (bad PDF or redacted)

  // Build per-chunk metadata by pulling run-level + document-level fields
  // from the Split Per-Document output (which still has them). PDF extract
  // byproducts (numpages, info, version) intentionally omitted.
  const s = splitItem.json;
  const baseMeta = {
    run_id: s.run_id,
    deal_id: s.deal_id,
    company_name: s.company_name,
    timestamp_started: s.timestamp_started,
    source_manifest: s.source_manifest,
    document: s.document,
  };

  let pos = 0;
  let chunkIndex = 0;
  while (pos < text.length) {
    const end = Math.min(pos + CHUNK_CHARS, text.length);
    chunks.push({
      json: {
        ...baseMeta,
        chunk_index: chunkIndex,
        char_offset_start: pos,
        char_offset_end: end,
        page_estimate: Math.max(1, Math.ceil(pos / CHARS_PER_PAGE)),
        text: text.substring(pos, end),
      },
    });
    chunkIndex++;
    if (end >= text.length) break;
    pos = end - OVERLAP_CHARS;
  }
}

console.log(`Chunker emitted ${chunks.length} chunks from ${items.length} documents.`);
return chunks;

// Extract Embedding — Phase 3 task 3.3c
// ⚠ IMPORTANT: n8n's HTTP Request node REPLACES $json with the response
// body (not merge). So $input.item.json here is ONLY the Alicloud
// embeddings response; the chunk metadata has been dropped.
// We recover it by reaching back to the Text Chunker's output at the
// same item position via $('Text Chunker').item.
//
// Alicloud response shape:
//   { object: 'list',
//     data: [{ embedding: [0.1, -0.05, ...], index: 0, object: 'embedding' }],
//     model: 'text-embedding-v4',
//     usage: { prompt_tokens: 900, total_tokens: 900 } }

const response = $input.item.json;
// Reach back two nodes to get the original chunk metadata for this item.
// n8n preserves item-position ordering through HTTP Request in runOnce
// ForEachItem mode, so item i in Extract Embedding corresponds to
// item i in Text Chunker.
const chunk = $('Text Chunker').item.json;

const data = Array.isArray(response.data) ? response.data : [];
const embedding = data[0] && Array.isArray(data[0].embedding) ? data[0].embedding : null;
if (!embedding) {
  // Non-fatal: emit the item with embedding: null. Downstream retrieval
  // will skip chunks whose embedding is missing.
  console.log(`WARN: no embedding in response for chunk_index=${chunk.chunk_index}`);
}

// Extract usage for token accounting (logged for cost model refinement).
const usage = response.usage || {};

return {
  json: {
    run_id: chunk.run_id,
    deal_id: chunk.deal_id,
    company_name: chunk.company_name,
    timestamp_started: chunk.timestamp_started,
    source_manifest: chunk.source_manifest,
    document: chunk.document,
    chunk_index: chunk.chunk_index,
    char_offset_start: chunk.char_offset_start,
    char_offset_end: chunk.char_offset_end,
    page_estimate: chunk.page_estimate,
    text: chunk.text,
    embedding,
    embedding_dim: embedding ? embedding.length : 0,
    embedding_tokens: usage.prompt_tokens || 0,
  },
};

// Aggregate Vector Store — Phase 3 task 3.3d
// Folds all per-chunk items (from Extract Embedding) into ONE item
// carrying the full in-memory vector store. Downstream specialist
// agents run cosine-similarity retrieval against `chunks[]`, optionally
// filtering to a single document via chunk.file_id.
//
// Path A (hand-rolled retrieval, decided 2026-04-24T18:30) — we do NOT
// use n8n's LangChain Simple Vector Store. Our store is just a JSON
// array held in a single workflow item.
//
// Input: N items (one per chunk), each with run-level + per-chunk meta.
// Output: 1 item:
//   { run_id, deal_id, company_name, timestamp_started, source_manifest,
//     chunks: [{ file_id, source_name, source_type, filename,
//                chunk_index, char_offset_start, char_offset_end,
//                page_estimate, text, embedding }],
//     meta: { chunk_count, total_embedding_tokens, documents_ingested } }

const items = $input.all();
if (items.length === 0) {
  throw new Error('Aggregate Vector Store received 0 items. Ingestion broke upstream.');
}

// Run-level metadata comes from the first item; all items share it.
const first = items[0].json;

// Flatten each chunk into a retrieval-ready shape. Nested `document`
// object is hoisted up so retrieval filters can access .file_id etc.
// without deep-path access.
const chunks = items.map((item) => {
  const j = item.json || {};
  const doc = j.document || {};
  return {
    file_id: doc.file_id || null,
    source_name: doc.source_name || 'Unknown Source',
    source_type: doc.source_type || 'regulatory_filing',
    filename: doc.filename || null,
    chunk_index: j.chunk_index ?? null,
    char_offset_start: j.char_offset_start ?? null,
    char_offset_end: j.char_offset_end ?? null,
    page_estimate: j.page_estimate ?? null,
    text: j.text || '',
    embedding: Array.isArray(j.embedding) ? j.embedding : null,
  };
});

const totalTokens = items.reduce(
  (acc, i) => acc + (i.json?.embedding_tokens || 0),
  0
);
const documentsIngested = Array.from(
  new Set(chunks.map((c) => c.source_name))
);

const validChunks = chunks.filter((c) => c.embedding && c.embedding.length > 0);
if (validChunks.length === 0) {
  throw new Error('No chunks have valid embeddings — retrieval will be impossible.');
}
if (validChunks.length < chunks.length) {
  console.log(`WARN: ${chunks.length - validChunks.length} of ${chunks.length} chunks lacked embeddings; dropped.`);
}

console.log(`Vector store ready: ${validChunks.length} chunks across ${documentsIngested.length} documents; ${totalTokens} embedding tokens total.`);

return {
  json: {
    run_id: first.run_id,
    deal_id: first.deal_id,
    company_name: first.company_name,
    timestamp_started: first.timestamp_started,
    source_manifest: first.source_manifest,
    chunks: validChunks,
    meta: {
      chunk_count: validChunks.length,
      total_embedding_tokens: totalTokens,
      documents_ingested: documentsIngested,
    },
  },
};

// Prepare Extraction Queries — Phase 3 task 3.5
// Build one retrieval query item per (document, section) plus one union query.
// Query embeddings are scored against the hand-rolled chunk store in the next node.

const item = $input.all()[0]?.json;
if (!item) throw new Error('Prepare Extraction Queries expected the Aggregate Vector Store item.');

const SECTION_QUERIES = [
  { name: 'company_overview',      top_k: 5, text: 'company overview what does the company do founding year headcount headquarters geography' },
  { name: 'investment_thesis',     top_k: 5, text: 'investment thesis bull case why win strategic rationale growth narrative' },
  { name: 'market_opportunity',    top_k: 5, text: 'tam sam som market opportunity total addressable market growth drivers' },
  { name: 'business_model',        top_k: 5, text: 'business model revenue streams pricing monetization how company makes money' },
  { name: 'financial_performance', top_k: 5, text: 'financial performance revenue growth gross margin operating loss cash balance burn' },
  { name: 'unit_economics',        top_k: 5, text: 'unit economics cac ltv payback retention unit economics efficiency' },
  { name: 'competitive_position',  top_k: 5, text: 'competitive position competitors competition moat differentiation advantage' },
  { name: 'management_assessment', top_k: 5, text: 'management assessment executives founder ceo cfo key personnel key person risk' },
  { name: 'customer_profile',      top_k: 5, text: 'customer profile customer concentration top customer top 1 top 2 top 5 retention' },
  { name: 'risk_factors',          top_k: 5, text: 'risk factors disclosed risks material weakness going concern related party debt concentration' },
  { name: 'management_claims',     top_k: 5, text: 'management claims management states claims asserts leadership performance forward-looking' },
  { name: 'deal_structure',        top_k: 5, text: 'deal structure valuation amount raised use of proceeds offering ipo shares' },
];
const UNION_QUERY = {
  name: 'union',
  top_k: 8,
  text: 'risk factors customer concentration material weaknesses related party transactions going concern debt structure'
};

const docs = Array.from(new Map(
  (item.chunks || []).map((c) => [
    c.source_name,
    {
      file_id: c.file_id,
      source_name: c.source_name,
      source_type: c.source_type,
      filename: c.filename,
    },
  ])
).values());

const out = [];
for (const doc of docs) {
  for (const q of SECTION_QUERIES) {
    out.push({
      json: {
        run_id: item.run_id,
        deal_id: item.deal_id,
        company_name: item.company_name,
        timestamp_started: item.timestamp_started,
        source_manifest: item.source_manifest,
        file_id: doc.file_id,
        source_name: doc.source_name,
        source_type: doc.source_type,
        filename: doc.filename,
        query_name: q.name,
        query_text: q.text,
        top_k: q.top_k,
        is_union: false,
      },
    });
  }
  out.push({
    json: {
      run_id: item.run_id,
      deal_id: item.deal_id,
      company_name: item.company_name,
      timestamp_started: item.timestamp_started,
      source_manifest: item.source_manifest,
      file_id: doc.file_id,
      source_name: doc.source_name,
      source_type: doc.source_type,
      filename: doc.filename,
      query_name: UNION_QUERY.name,
      query_text: UNION_QUERY.text,
      top_k: UNION_QUERY.top_k,
      is_union: true,
    },
  });
}

console.log(`Prepared ${out.length} extraction retrieval queries across ${docs.length} documents.`);
return out;

// Rank Extraction Chunks — Phase 3 task 3.5
// Score document-local chunks against the query embedding and select top-k.

const response = $input.item.json;
const queryItem = $('Prepare Extraction Queries').item.json;
const store = $('Aggregate Vector Store').all()[0]?.json;
if (!store) throw new Error('Aggregate Vector Store item unavailable in Rank Extraction Chunks.');

const queryEmbedding = response.data?.[0]?.embedding;
if (!Array.isArray(queryEmbedding) || queryEmbedding.length === 0) {
  throw new Error(`No query embedding returned for ${queryItem.source_name} / ${queryItem.query_name}`);
}

function cosineSimilarity(a, b) {
  let dot = 0;
  let normA = 0;
  let normB = 0;
  const len = Math.min(a.length, b.length);
  for (let i = 0; i < len; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return -1;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

const candidates = (store.chunks || []).filter(
  (c) => c.source_name === queryItem.source_name && Array.isArray(c.embedding) && c.embedding.length > 0
);
const ranked = candidates
  .map((c) => ({
    score: cosineSimilarity(queryEmbedding, c.embedding),
    chunk: {
      source_name: c.source_name,
      page_estimate: c.page_estimate,
      chunk_index: c.chunk_index,
      text: c.text,
      score: cosineSimilarity(queryEmbedding, c.embedding),
    },
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, queryItem.top_k);

return {
  json: {
    run_id: queryItem.run_id,
    deal_id: queryItem.deal_id,
    company_name: queryItem.company_name,
    timestamp_started: queryItem.timestamp_started,
    source_manifest: queryItem.source_manifest,
    file_id: queryItem.file_id,
    source_name: queryItem.source_name,
    source_type: queryItem.source_type,
    filename: queryItem.filename,
    query_name: queryItem.query_name,
    query_text: queryItem.query_text,
    top_k: queryItem.top_k,
    is_union: queryItem.is_union,
    selected_chunks: ranked.map((r) => r.chunk),
    query_embedding_tokens: response.usage?.prompt_tokens || 0,
  },
};

// Aggregate Extraction Context — Phase 3 task 3.5
// Regroup ranked query hits into one item per document with `chunks` and `union_chunks`.
// Cap the final prompt context so large filings do not effectively stuff the whole document.

const items = $input.all();
if (items.length === 0) throw new Error('Aggregate Extraction Context received 0 ranked query items.');

const MAX_REGULAR_CHUNKS = 24;
const MAX_UNION_CHUNKS = 6;

function selectChunks(chunks, limit) {
  const bestByKey = new Map();
  for (const c of chunks) {
    const key = `${c.source_name}::${c.chunk_index}`;
    const prev = bestByKey.get(key);
    const score = typeof c.score === 'number' ? c.score : -1;
    const prevScore = prev && typeof prev.score === 'number' ? prev.score : -1;
    if (!prev || score > prevScore) bestByKey.set(key, c);
  }
  return Array.from(bestByKey.values())
    .sort((a, b) => {
      const scoreA = typeof a.score === 'number' ? a.score : -1;
      const scoreB = typeof b.score === 'number' ? b.score : -1;
      if (scoreB !== scoreA) return scoreB - scoreA;
      return (a.chunk_index ?? 0) - (b.chunk_index ?? 0);
    })
    .slice(0, limit)
    .sort((a, b) => (a.chunk_index ?? 0) - (b.chunk_index ?? 0))
    .map(({ score, ...rest }) => rest);
}

const groups = new Map();
for (const item of items) {
  const j = item.json;
  const key = j.source_name;
  if (!groups.has(key)) {
    groups.set(key, {
      run_id: j.run_id,
      deal_id: j.deal_id,
      company_name: j.company_name,
      timestamp_started: j.timestamp_started,
      source_manifest: j.source_manifest,
      file_id: j.file_id,
      source_name: j.source_name,
      source_type: j.source_type,
      filename: j.filename,
      regular: [],
      union: [],
      total_query_embedding_tokens: 0,
    });
  }
  const g = groups.get(key);
  g.total_query_embedding_tokens += j.query_embedding_tokens || 0;
  if (j.is_union) g.union.push(...(j.selected_chunks || []));
  else g.regular.push(...(j.selected_chunks || []));
}

const out = Array.from(groups.values()).map((g) => {
  const selectedRegular = selectChunks(g.regular, MAX_REGULAR_CHUNKS);
  const selectedUnion = selectChunks(g.union, MAX_UNION_CHUNKS);
  return {
    json: {
      run_id: g.run_id,
      deal_id: g.deal_id,
      company_name: g.company_name,
      timestamp_started: g.timestamp_started,
      source_manifest: g.source_manifest,
      file_id: g.file_id,
      source_name: g.source_name,
      source_type: g.source_type,
      filename: g.filename,
      chunks: selectedRegular,
      union_chunks: selectedUnion,
      retrieval_meta: {
        selected_chunk_count: selectedRegular.length,
        selected_union_chunk_count: selectedUnion.length,
        total_query_embedding_tokens: g.total_query_embedding_tokens,
      },
    },
  };
});

console.log(`Prepared extraction context for ${out.length} documents.`);
return out;

// Parse Extraction Response — Phase 3 task 3.5
// Normalizes the OpenAI-compatible chat response into one Extraction result per document.
// Also projects the model output back onto the exact Extraction schema shape.

const response = $input.item.json;
const request = $('Build Extraction Request').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error(`Extraction response missing message content for ${request.source_name}`);
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Extraction JSON parse failed for ${request.source_name}: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

function obj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : {};
}
function strOrNull(v) {
  return typeof v === 'string' ? v : null;
}
function numOrNull(v) {
  return typeof v === 'number' && Number.isFinite(v) ? v : null;
}
function boolOrNull(v) {
  return typeof v === 'boolean' ? v : null;
}
function stringArray(v) {
  return Array.isArray(v) ? v.filter((x) => typeof x === 'string') : [];
}
function citationOrNull(v) {
  return typeof v === 'string' ? v : null;
}
function metricWithPeriod(v) {
  const x = obj(v);
  return {
    value: numOrNull(x.value),
    period: strOrNull(x.period),
    citation: citationOrNull(x.citation),
  };
}
function metricNoPeriod(v) {
  const x = obj(v);
  return {
    value: numOrNull(x.value),
    citation: citationOrNull(x.citation),
  };
}
function arrayOfClaims(v, keyName) {
  if (!Array.isArray(v)) return [];
  return v
    .map((x) => obj(x))
    .map((x) => ({ [keyName]: strOrNull(x[keyName]), citation: citationOrNull(x.citation) }))
    .filter((x) => typeof x[keyName] === 'string' && typeof x.citation === 'string');
}

const facts = obj(parsed.extracted_facts);
const sanitized = {
  source_name: request.source_name,
  source_type: request.source_type,
  extracted_facts: {
    company_overview: {
      description: strOrNull(obj(facts.company_overview).description),
      founding_year: numOrNull(obj(facts.company_overview).founding_year),
      headcount: numOrNull(obj(facts.company_overview).headcount),
      geography: strOrNull(obj(facts.company_overview).geography),
      citations: stringArray(obj(facts.company_overview).citations),
    },
    investment_thesis: {
