parameters.jsCode:
// Parse Contradiction Tool Calls — Phase 3 task 3.6
// Fan out one model response into N tool-call items.

const response = $input.all()[0]?.json;
const request = $('Build Contradiction Request').all()[0]?.json;
if (!response) throw new Error('Parse Contradiction Tool Calls received 0 input items.');
if (!request) throw new Error('Build Contradiction Request item unavailable.');

const message = response.choices?.[0]?.message || {};
const toolCalls = Array.isArray(message.tool_calls) ? message.tool_calls : [];

let assistantContent = message.content;
if (Array.isArray(assistantContent)) {
  assistantContent = assistantContent.map((p) => p?.text || '').join('');
}
if (toolCalls.length === 0) {
  throw new Error(`Contradiction turn-1 returned no tool_calls. D-2 tool-use likely failed. Raw content: ${String(assistantContent || '').slice(0, 500)}`);
}

const out = [];
for (const call of toolCalls) {
  if (call?.type !== 'function' || call?.function?.name !== 'retrieve_document') continue;

  let args;
  try {
    args = JSON.parse(call.function.arguments || '{}');
  } catch (err) {
    throw new Error(`Failed to parse retrieve_document arguments: ${err.message}\nRaw: ${call.function.arguments || ''}`);
  }

  const sourceName = typeof args.source_name === 'string' ? args.source_name.trim() : '';
  const query = typeof args.query === 'string' ? args.query.trim() : '';
  const kRaw = typeof args.k === 'number' ? args.k : parseInt(args.k, 10);
  const k = Number.isFinite(kRaw) ? Math.max(1, Math.min(5, kRaw)) : 5;

  if (!sourceName) throw new Error('retrieve_document tool call missing source_name');
  if (!query) throw new Error('retrieve_document tool call missing query');

  out.push({
    json: {
      ...request,
      turn1_message: {
        role: 'assistant',
        content: typeof assistantContent === 'string' ? assistantContent : null,
        tool_calls: toolCalls,
      },
      tool_call_id: call.id,
      source_name: sourceName,
      query,
      k,
    },
  });
}

if (out.length === 0) {
  throw new Error('No usable retrieve_document tool calls found in turn-1 response.');
}

return out;

// Rank Contradiction Chunks — Phase 3 task 3.6
// Implements the retrieve_document tool against the existing aggregate chunk store.

const response = $input.item.json;
const req = $('Parse Contradiction Tool Calls').item.json;
const store = $('Aggregate Vector Store').all()[0]?.json;
if (!store) throw new Error('Aggregate Vector Store item unavailable in Rank Contradiction Chunks.');

const queryEmbedding = response.data?.[0]?.embedding;
if (!Array.isArray(queryEmbedding) || queryEmbedding.length === 0) {
  throw new Error(`No contradiction query embedding returned for ${req.source_name}`);
}

function cosineSimilarity(a, b) {
  let dot = 0;
  let normA = 0;
  let normB = 0;
  const len = Math.min(a.length, b.length);
  for (let i = 0; i < len; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return -1;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

const ranked = (store.chunks || [])
  .filter((c) => c.source_name === req.source_name && Array.isArray(c.embedding) && c.embedding.length > 0)
  .map((c) => ({
    score: cosineSimilarity(queryEmbedding, c.embedding),
    chunk: {
      source_name: c.source_name,
      page_estimate: c.page_estimate,
      chunk_index: c.chunk_index,
      text: c.text,
    },
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, req.k)
  .map((r) => r.chunk);

return {
  json: {
    ...req,
    tool_result: {
      source_name: req.source_name,
      query: req.query,
      chunks: ranked,
    },
    query_embedding_tokens: response.usage?.prompt_tokens || 0,
  },
};

// Aggregate Contradiction Tool Results — Phase 3 task 3.6
// Reconstruct the tool conversation messages for the final synthesis turn.

const items = $input.all();
if (items.length === 0) throw new Error('Aggregate Contradiction Tool Results received 0 tool results.');

const first = items[0].json;
const toolMessages = items.map((item) => ({
  role: 'tool',
  tool_call_id: item.json.tool_call_id,
  name: 'retrieve_document',
  content: JSON.stringify(item.json.tool_result),
}));
const totalQueryTokens = items.reduce((acc, item) => acc + (item.json.query_embedding_tokens || 0), 0);

return {
  json: {
    run_id: first.run_id,
    deal_id: first.deal_id,
    company_name: first.company_name,
    timestamp_started: first.timestamp_started,
    source_manifest: first.source_manifest,
    extraction_outputs: first.extraction_outputs,
    system_prompt: first.system_prompt,
    user_message: first.user_message,
    turn1_message: first.turn1_message,
    messages: [
      { role: 'system', content: first.system_prompt },
      { role: 'user', content: first.user_message },
      {
        role: 'assistant',
        content: first.turn1_message?.content ?? null,
        tool_calls: first.turn1_message?.tool_calls || [],
      },
      ...toolMessages,
    ],
    contradiction_retrieval_meta: {
      tool_call_count: items.length,
      total_query_embedding_tokens: totalQueryTokens,
      tool_results: items.map((item) => item.json.tool_result),
    },
  },
};

// Parse Contradiction Response — Phase 3 task 3.6
// Normalize the final tool-use synthesis into the exact Contradiction schema shape.

const response = $input.item.json;
const request = $('Aggregate Contradiction Tool Results').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error('Contradiction final response missing message content.');
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Contradiction JSON parse failed: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

function obj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : {};
}
function str(v) {
  return typeof v === 'string' ? v : null;
}
function stringArray(v) {
  return Array.isArray(v) ? v.filter((x) => typeof x === 'string') : [];
}
function validSeverity(v) {
  return ['HIGH', 'MEDIUM', 'LOW'].includes(v) ? v : null;
}
function validContradictionClass(v) {
  return ['DISPUTED', 'UNSUPPORTED'].includes(v) ? v : null;
}
function validVerifiedClass(v) {
  return ['CORROBORATED', 'UNCONTRADICTED'].includes(v) ? v : null;
}

const contradictions = Array.isArray(parsed.contradictions)
  ? parsed.contradictions
      .map((x) => obj(x))
      .map((x) => ({
        claim: str(x.claim),
        sources_making_claim: stringArray(x.sources_making_claim),
        contradicting_evidence: Array.isArray(x.contradicting_evidence)
          ? x.contradicting_evidence
              .map((e) => obj(e))
              .map((e) => ({
                source: str(e.source),
                citation: str(e.citation),
                evidence: str(e.evidence),
              }))
              .filter((e) => e.source && e.citation && e.evidence)
          : [],
        nature_of_conflict: str(x.nature_of_conflict) || '',
        severity: validSeverity(x.severity),
        classification: validContradictionClass(x.classification),
      }))
      .filter((x) => x.claim && x.sources_making_claim.length > 0 && x.severity && x.classification)
      .filter((x) => x.classification !== 'DISPUTED' || x.contradicting_evidence.length > 0)
  : [];

const verifiedClaims = Array.isArray(parsed.verified_claims)
  ? parsed.verified_claims
      .map((x) => obj(x))
      .map((x) => ({
        claim: str(x.claim),
        sources: stringArray(x.sources),
        classification: validVerifiedClass(x.classification),
      }))
      .filter((x) => x.claim && x.sources.length > 0 && x.classification)
  : [];

return {
  json: {
    run_id: request.run_id,
    deal_id: request.deal_id,
    company_name: request.company_name,
    timestamp_started: request.timestamp_started,
    source_manifest: request.source_manifest,
    contradiction_output: {
      contradictions,
      verified_claims: verifiedClaims,
    },
    contradiction_retrieval_meta: request.contradiction_retrieval_meta,
    llm_usage: response.usage || {},
    llm_model: response.model || $env.ALICLOUD_MODEL,
  },
};

// Prepare Gap Analysis Inputs — Phase 3 task 3.7
// Aggregate inputs for the Gap Analysis agent: per-document extraction outputs,
// the contradiction output, and a union retrieval query for LP-checklist coverage.

const items = $input.all();
if (items.length === 0) {
  throw new Error('Prepare Gap Analysis Inputs received 0 contradiction outputs.');
}

const contradictionItem = items[0].json;
if (!contradictionItem.contradiction_output) {
  throw new Error('Parse Contradiction Response did not emit contradiction_output.');
}

const aggregated = $('Aggregate Contradiction Inputs').all()[0]?.json;
if (!aggregated) {
  throw new Error('Aggregate Contradiction Inputs item unavailable for Gap Analysis.');
}

const extractionOutputs = aggregated.extraction_outputs || [];
if (extractionOutputs.length === 0) {
  throw new Error('No extraction_outputs available for Gap Analysis.');
}

return {
  json: {
    run_id: contradictionItem.run_id,
    deal_id: contradictionItem.deal_id,
    company_name: contradictionItem.company_name,
    timestamp_started: contradictionItem.timestamp_started,
    source_manifest: contradictionItem.source_manifest,
    extraction_outputs: extractionOutputs,
    contradiction_output: contradictionItem.contradiction_output,
    query: 'audited financials unit economics customer concentration cohort retention covenants related party transactions litigation board composition customer references intellectual property',
    k: 6,
  },
};

// Rank Gap Analysis Chunks — Phase 3 task 3.7
// Union retrieval across ALL documents (no source_name filter), top-k chunks for
// the LP-checklist coverage query. Per design plan §2.6.

const response = $input.item.json;
const req = $('Prepare Gap Analysis Inputs').item.json;
const store = $('Aggregate Vector Store').all()[0]?.json;
if (!store) throw new Error('Aggregate Vector Store item unavailable in Rank Gap Analysis Chunks.');

const queryEmbedding = response.data?.[0]?.embedding;
if (!Array.isArray(queryEmbedding) || queryEmbedding.length === 0) {
  throw new Error('No Gap Analysis query embedding returned.');
}

function cosineSimilarity(a, b) {
  let dot = 0;
  let normA = 0;
  let normB = 0;
  const len = Math.min(a.length, b.length);
  for (let i = 0; i < len; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return -1;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

const k = req.k || 6;
const ranked = (store.chunks || [])
  .filter((c) => Array.isArray(c.embedding) && c.embedding.length > 0)
  .map((c) => ({
    score: cosineSimilarity(queryEmbedding, c.embedding),
    chunk: {
      source_name: c.source_name,
      page_estimate: c.page_estimate,
      chunk_index: c.chunk_index,
      text: c.text,
    },
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, k)
  .map((r) => r.chunk);

return {
  json: {
    ...req,
    union_chunks: ranked,
    gap_query_embedding_tokens: response.usage?.prompt_tokens || 0,
  },
};

// Parse Gap Analysis Response — Phase 3 task 3.7
// Normalize the model output into the exact GapAnalysisOutput schema shape.

const response = $input.item.json;
const request = $('Build Gap Analysis Request').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error('Gap Analysis response missing message content.');
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Gap Analysis JSON parse failed: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

const VALID_CATEGORIES = ['financial_diligence', 'commercial_diligence', 'operational_diligence', 'legal_regulatory'];
const VALID_IMPORTANCE = ['HIGH', 'MEDIUM', 'LOW'];

function obj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : {};
}
function str(v) {
  return typeof v === 'string' ? v : null;
}

const items = Array.isArray(parsed.missing_information) ? parsed.missing_information : [];
const missing = items
  .map((x) => obj(x))
  .map((x) => ({
    category: VALID_CATEGORIES.includes(x.category) ? x.category : null,
    item: str(x.item),
    importance: VALID_IMPORTANCE.includes(x.importance) ? x.importance : null,
    suggested_source: typeof x.suggested_source === 'string' ? x.suggested_source : undefined,
  }))
  .filter((x) => x.category && x.item && x.item.trim().length > 0 && x.importance)
  .map((x) => {
    const out = { category: x.category, item: x.item, importance: x.importance };
    if (x.suggested_source !== undefined) out.suggested_source = x.suggested_source;
    return out;
  });

return {
  json: {
    run_id: request.run_id,
    deal_id: request.deal_id,
    company_name: request.company_name,
    timestamp_started: request.timestamp_started,
    source_manifest: request.source_manifest,
    gap_analysis_output: { missing_information: missing },
    gap_retrieval_meta: {
      union_chunk_count: (request.union_chunks || []).length,
      query_embedding_tokens: request.gap_query_embedding_tokens || 0,
    },
    llm_usage: response.usage || {},
    llm_model: response.model || $env.ALICLOUD_MODEL,
  },
};

// Run Red Flag Detector — Phase 3 task 3.8
// Deterministic JS only. No LLM. No Math.random. No time-dependent logic.
// Per I-2 in .claude/memory/context.md.
//
// IMPLEMENTATION NOTE (D-6 doubled-code surface):
// The detector module body below is pasted from code/red-flag-detector.js.
// If that file changes, this node must be re-pasted (or use the future
// scripts/inject-prompts.js mitigation when 3.11 lands). Reference unit
// tests live at code/test/red-flag-detector.test.js (37/37 passing per
// Phase 2 Receipt) — they validate the canonical module, not this paste.

// =====================================================================
// Inputs
// =====================================================================

const aggregated = $('Aggregate Contradiction Inputs').all()[0]?.json;
if (!aggregated) {
  throw new Error('Aggregate Contradiction Inputs item unavailable for Red Flag Detector.');
}

const store = $('Aggregate Vector Store').all()[0]?.json;
if (!store) {
  throw new Error('Aggregate Vector Store item unavailable for Red Flag Detector.');
}

const upstreamItems = $input.all();
if (upstreamItems.length === 0) {
  throw new Error('Run Red Flag Detector received 0 input items.');
}
const upstream = upstreamItems[0].json;

const extractionOutputs = aggregated.extraction_outputs || [];

// Reconstruct per-document raw text from the aggregate chunk store.
// Per design plan §2.7 (updated by D-6): concatenate chunks by source_name,
// in chunk_index order, to recover per-document text for regex-based detectors.

const sourceTypeBySource = {};
for (const entry of (aggregated.source_manifest || [])) {
  if (entry && entry.source_name && entry.source_type) {
    sourceTypeBySource[entry.source_name] = entry.source_type;
  }
}

const chunksBySource = {};
for (const c of (store.chunks || [])) {
  if (!c || !c.source_name) continue;
  if (!chunksBySource[c.source_name]) chunksBySource[c.source_name] = [];
  chunksBySource[c.source_name].push(c);
}
for (const list of Object.values(chunksBySource)) {
  list.sort((a, b) => (a.chunk_index || 0) - (b.chunk_index || 0));
}

const documentsRaw = Object.entries(chunksBySource).map(([source_name, chunks]) => ({
  source_name,
  source_type: sourceTypeBySource[source_name] || 'unknown',
  text: chunks.map((c) => c.text || '').join('\n\n'),
}));

// =====================================================================
// Detector module — pasted from code/red-flag-detector.js
// (CommonJS exports stripped; functions are in this Code-node scope.)
// =====================================================================

// code/red-flag-detector.js
// ---------------------------------------------------------------------
// Deterministic red-flag detection. No LLM calls. No Math.random.
// No time-dependent logic. See invariant I-2 in .claude/memory/context.md.
//
// Design plan §2.7 is the authoritative spec.
// Output shape matches schemas/agent-output-schemas.json#/$defs/RedFlagDetectorOutput.
// ---------------------------------------------------------------------
// 'use strict' (sandbox-implicit)

// ----- Thresholds (all named constants; no magic numbers inline) -----
const CUSTOMER_CONCENTRATION_HIGH_PCT     = 30;   // single customer % of revenue
const CUSTOMER_CONCENTRATION_EXTREME_PCT  = 50;   // single customer % of revenue
const CUSTOMER_CONCENTRATION_TOP2_EXTREME = 70;   // top 2 combined % of revenue
const RELATED_PARTY_THRESHOLD_PCT         = 5;    // of revenue
const REVENUE_GROWTH_ANOMALOUS_PCT        = 500;  // YoY growth flag
const RUNWAY_SHORT_MONTHS                 = 12;   // cash / monthly burn
const AUDITOR_CHANGE_WINDOW_YEARS         = 2;    // (reserved; not used by current detector)

// ----- Regex patterns (with negation guards; per design plan §2.7) -----
// Rule: positive match AND no negation within the SAME sentence.
// All flags are case-insensitive; no /g — single match is sufficient.

const MATERIAL_WEAKNESS_POS = /(?:identified|disclose[ds]?|found|reported|existence of|presence of)[^.!?]{0,60}material weakness(?:es)?/i;
const MATERIAL_WEAKNESS_NEG = /(?:no |without |absence of |did not (?:identify|find|disclose|report) (?:any )?|no such )material weakness/i;

const GOING_CONCERN_POS = /(?:substantial doubt|going concern|ability to continue as a going concern)/i;
const GOING_CONCERN_NEG = /(?:no substantial doubt|without substantial doubt|no going concern|absence of going concern)/i;

const RELATED_PARTY_CONTEXT = /related part(?:y|ies) transaction/i;

const AUDITOR_CHANGE_POS = /(?:chang(?:e|ed|ing) of auditor|appoint(?:ed|ment of) new auditor|dismiss(?:ed|al of) (?:our|the) auditor)/i;
const AUDITOR_CHANGE_NEG = /(?:no (?:chang(?:e|es) of )?auditor|auditor (?:has )?not chang(?:e|ed))/i;

const DUAL_CLASS_POS = /(?:class [AB] common stock|super[- ]?voting|triple[- ]?class|dual[- ]?class share structure)/i;

const S1_WITHDRAWN_POS = /(?:previously (?:filed and )?withdrew|withdrawal of (?:prior |previous )?registration|previous S-?1 (?:was )?withdrawn)/i;

// ----- Helpers -----

/**
 * Split raw text into sentences for negation-context checking.
 * Handles ., !, ? followed by whitespace. Naive but sufficient for regulatory prose.
 * @param {string} text
 * @returns {string[]}
 */
function splitSentences(text) {
  if (!text) return [];
  return text.split(/(?<=[.!?])\s+/).map(s => s.trim()).filter(Boolean);
}

/**
 * True iff POS matches inside some sentence AND that same sentence does NOT match NEG.
 * @param {string} text
 * @param {RegExp} pos
 * @param {RegExp|null} neg
 * @returns {{matched: boolean, sentence: string|null}}
 */
function matchWithNegationGuard(text, pos, neg) {
  for (const s of splitSentences(text)) {
    if (pos.test(s) && !(neg && neg.test(s))) {
      return { matched: true, sentence: s };
    }
  }
  return { matched: false, sentence: null };
}

/**
 * Scope raw text to regulatory_filing sources only for regex flags.
 * @param {Array<{source_name: string, source_type: string, text: string}>} documentsRaw
 * @returns {string} concatenated regulatory-filing text
 */
function regulatoryTextOnly(documentsRaw) {
  return (documentsRaw || [])
    .filter(d => d && d.source_type === 'regulatory_filing')
    .map(d => d.text || '')
    .join('\n\n');
}

/**
 * Iterate over regulatory_filing documents and return the first
 * {source_name, sentence} where POS matches without NEG in the same sentence.
 * Preserves per-document source attribution (lost by regulatoryTextOnly).
 * @returns {{source_name: string, sentence: string}|null}
 */
function firstRegulatoryMatch(documentsRaw, pos, neg) {
  for (const d of documentsRaw || []) {
    if (!d || d.source_type !== 'regulatory_filing') continue;
    const r = matchWithNegationGuard(d.text || '', pos, neg);
    if (r.matched) return { source_name: d.source_name || 'Regulatory filing', sentence: r.sentence };
  }
  return null;
}

/**
 * Safely read a nested numeric value from an ExtractionOutput-shaped object.
 * Returns null if any level is missing or the terminal value isn't a number.
 */
function readNum(obj, path) {
  let node = obj;
  for (const k of path) {
    if (node == null || typeof node !== 'object') return null;
    node = node[k];
  }
  return typeof node === 'number' && !Number.isNaN(node) ? node : null;
}

// ----- Individual detectors -----

/**
 * customer_concentration_high — MEDIUM. Single customer >=30% but <50% of revenue.
 * (Suppressed when the EXTREME threshold is also met — EXTREME supersedes.)
 */
function _detectCustomerConcentrationHigh(extractedPerDoc) {
  for (const doc of extractedPerDoc || []) {
    const top1 = readNum(doc, ['extracted_facts', 'customer_profile', 'concentration_top_1']);
    const top2 = readNum(doc, ['extracted_facts', 'customer_profile', 'concentration_top_2']);
    // EXTREME condition: don't double-flag
    const isExtreme =
      (top1 != null && top1 >= CUSTOMER_CONCENTRATION_EXTREME_PCT) ||
      (top2 != null && top2 >= CUSTOMER_CONCENTRATION_TOP2_EXTREME);
    if (isExtreme) continue;
    if (top1 != null && top1 >= CUSTOMER_CONCENTRATION_HIGH_PCT) {
      return {
        flag_type: 'customer_concentration_high',
        severity: 'MEDIUM',
        evidence: {
          actual_value: top1,
          threshold: CUSTOMER_CONCENTRATION_HIGH_PCT,
          source: doc.source_name || 'Extraction',
          raw_text: null,
        },
      };
    }
  }
  return null;
}

/**
 * customer_concentration_extreme — HIGH. Single customer >=50% OR top-2 combined >=70%.
 */
function _detectCustomerConcentrationExtreme(extractedPerDoc) {
  for (const doc of extractedPerDoc || []) {
    const top1 = readNum(doc, ['extracted_facts', 'customer_profile', 'concentration_top_1']);
    const top2 = readNum(doc, ['extracted_facts', 'customer_profile', 'concentration_top_2']);
    if (top1 != null && top1 >= CUSTOMER_CONCENTRATION_EXTREME_PCT) {
      return {
        flag_type: 'customer_concentration_extreme',
        severity: 'HIGH',
        evidence: {
          actual_value: top1,
          threshold: CUSTOMER_CONCENTRATION_EXTREME_PCT,
          source: doc.source_name || 'Extraction',
          raw_text: null,
        },
      };
    }
    if (top2 != null && top2 >= CUSTOMER_CONCENTRATION_TOP2_EXTREME) {
      return {
        flag_type: 'customer_concentration_extreme',
        severity: 'HIGH',
        evidence: {
          actual_value: top2,
          threshold: CUSTOMER_CONCENTRATION_TOP2_EXTREME,
          source: doc.source_name || 'Extraction',
          raw_text: null,
        },
      };
    }
  }
  return null;
}

/**
 * material_weakness — HIGH. Positive regex match in regulatory filing, no negation.
 */
function _detectMaterialWeakness(documentsRaw) {
  const m = firstRegulatoryMatch(documentsRaw, MATERIAL_WEAKNESS_POS, MATERIAL_WEAKNESS_NEG);
  if (!m) return null;
  return {
    flag_type: 'material_weakness',
    severity: 'HIGH',
    evidence: {
      actual_value: 'disclosed',
      threshold: null,
      source: m.source_name,
      raw_text: m.sentence,
    },
  };
}

/**
 * going_concern — HIGH. Positive regex match, no negation.
 */
function _detectGoingConcern(documentsRaw) {
  const m = firstRegulatoryMatch(documentsRaw, GOING_CONCERN_POS, GOING_CONCERN_NEG);
  if (!m) return null;
  return {
    flag_type: 'going_concern',
    severity: 'HIGH',
    evidence: {
      actual_value: 'disclosed',
      threshold: null,
      source: m.source_name,
      raw_text: m.sentence,
    },
  };
}

/**
 * related_party_above_threshold — MEDIUM. Regex match for related-party context
 * in a regulatory filing (our ExtractionOutput schema doesn't yet carry a
 * `related_party_pct_of_revenue` number, so we detect presence-in-text only).
 */
function _detectRelatedPartyAboveThreshold(extractedPerDoc, documentsRaw) {
  for (const d of documentsRaw || []) {
    if (!d || d.source_type !== 'regulatory_filing') continue;
    for (const s of splitSentences(d.text || '')) {
      if (RELATED_PARTY_CONTEXT.test(s)) {
        return {
          flag_type: 'related_party_above_threshold',
          severity: 'MEDIUM',
          evidence: {
            actual_value: 'disclosed',
            threshold: RELATED_PARTY_THRESHOLD_PCT,
            source: d.source_name || 'Regulatory filing',
            raw_text: s,
          },
        };
      }
    }
  }
  return null;
}

/**
 * revenue_growth_anomalous — LOW. YoY revenue growth >=500%.
 */
function _detectRevenueGrowthAnomalous(extractedPerDoc) {
  for (const doc of extractedPerDoc || []) {
    const g = readNum(doc, ['extracted_facts', 'financial_performance', 'revenue_growth_yoy', 'value']);
    if (g != null && g >= REVENUE_GROWTH_ANOMALOUS_PCT) {
      return {
        flag_type: 'revenue_growth_anomalous',
        severity: 'LOW',
        evidence: {
          actual_value: g,
          threshold: REVENUE_GROWTH_ANOMALOUS_PCT,
          source: doc.source_name || 'Extraction',
          raw_text: null,
        },
      };
    }
  }
  return null;
}

/**
 * burn_rate_runway_short — MEDIUM. cash / monthly_burn < 12 months.
 * Requires both cash_balance and monthly_burn to be extracted.
 */
function _detectBurnRateRunwayShort(extractedPerDoc) {
  for (const doc of extractedPerDoc || []) {
    const cash = readNum(doc, ['extracted_facts', 'financial_performance', 'cash_balance', 'value']);
    const burn = readNum(doc, ['extracted_facts', 'financial_performance', 'monthly_burn', 'value']);
    if (cash == null || burn == null || burn <= 0) continue;
    const runway = cash / burn;
    if (runway < RUNWAY_SHORT_MONTHS) {
      return {
        flag_type: 'burn_rate_runway_short',
        severity: 'MEDIUM',
        evidence: {
          actual_value: Math.round(runway * 10) / 10, // months, 1 dp
          threshold: RUNWAY_SHORT_MONTHS,
          source: doc.source_name || 'Extraction',
          raw_text: null,
        },
      };
    }
  }
  return null;
}

/**
 * auditor_change_recent — MEDIUM. Regex match with negation guard.
 */
function _detectAuditorChangeRecent(documentsRaw) {
  const m = firstRegulatoryMatch(documentsRaw, AUDITOR_CHANGE_POS, AUDITOR_CHANGE_NEG);
  if (!m) return null;
  return {
    flag_type: 'auditor_change_recent',
    severity: 'MEDIUM',
    evidence: {
      actual_value: 'disclosed',
      threshold: null,
      source: m.source_name,
      raw_text: m.sentence,
    },
  };
}

/**
 * dual_class_structure — LOW. Positive regex match (no negation guard needed —
 * mentions of dual/triple-class structure are rarely negated in regulatory prose).
 */
function _detectDualClassStructure(documentsRaw) {
  for (const d of documentsRaw || []) {
    if (!d || d.source_type !== 'regulatory_filing') continue;
    for (const s of splitSentences(d.text || '')) {
      if (DUAL_CLASS_POS.test(s)) {
        return {
          flag_type: 'dual_class_structure',
          severity: 'LOW',
          evidence: {
            actual_value: 'disclosed',
            threshold: null,
            source: d.source_name || 'Regulatory filing',
            raw_text: s,
          },
        };
      }
    }
  }
  return null;
}

/**
 * s1_previously_withdrawn — MEDIUM. Positive regex match.
 */
function _detectS1PreviouslyWithdrawn(documentsRaw) {
  for (const d of documentsRaw || []) {
    if (!d || d.source_type !== 'regulatory_filing') continue;
    for (const s of splitSentences(d.text || '')) {
      if (S1_WITHDRAWN_POS.test(s)) {
        return {
          flag_type: 's1_previously_withdrawn',
          severity: 'MEDIUM',
          evidence: {
            actual_value: 'disclosed',
            threshold: null,
            source: d.source_name || 'Regulatory filing',
            raw_text: s,
          },
        };
      }
    }
  }
  return null;
}

// ----- Public entrypoint -----

/**
 * Run all deterministic red-flag detectors against the deal packet.
 *
 * @param {Object[]} extractedFactsPerDocument
 *   Array of ExtractionOutput objects (one per ingested document),
 *   shape per schemas/agent-output-schemas.json#/$defs/ExtractionOutput.
 * @param {Object[]} documentsRaw
 *   Array of { source_name, source_type, text } — raw document text,
 *   used for regex-based detectors scoped to regulatory filings.
 * @returns {{ red_flags: Array<Object> }}
 *   Shape per schemas/agent-output-schemas.json#/$defs/RedFlagDetectorOutput.
 *   Every entry has `deterministic: true` — the governance field that
 *   distinguishes rule-based flags from LLM analysis in downstream consumers.
 */
function detectFlags(extractedFactsPerDocument, documentsRaw) {
  const detectors = [
    () => _detectCustomerConcentrationHigh(extractedFactsPerDocument),
    () => _detectCustomerConcentrationExtreme(extractedFactsPerDocument),
    () => _detectMaterialWeakness(documentsRaw),
    () => _detectGoingConcern(documentsRaw),
    () => _detectRelatedPartyAboveThreshold(extractedFactsPerDocument, documentsRaw),
    () => _detectRevenueGrowthAnomalous(extractedFactsPerDocument),
    () => _detectBurnRateRunwayShort(extractedFactsPerDocument),
    () => _detectAuditorChangeRecent(documentsRaw),
    () => _detectDualClassStructure(documentsRaw),
    () => _detectS1PreviouslyWithdrawn(documentsRaw),
  ];
  const red_flags = [];
  for (const d of detectors) {
    const flag = d();
    if (flag) red_flags.push({ ...flag, deterministic: true });
  }
  return { red_flags };
}

// =====================================================================
// Run detector + emit RedFlagDetectorOutput
// =====================================================================

const result = detectFlags(extractionOutputs, documentsRaw);

return {
  json: {
    run_id: upstream.run_id,
    deal_id: upstream.deal_id,
    company_name: upstream.company_name,
    timestamp_started: upstream.timestamp_started,
    source_manifest: upstream.source_manifest,
    red_flag_detector_output: result,
    rfd_meta: {
      doc_count: documentsRaw.length,
      regulatory_filing_count: documentsRaw.filter((d) => d.source_type === 'regulatory_filing').length,
      total_chunks: (store.chunks || []).length,
    },
  },
};

