    company_name: upstream.company_name,
    timestamp_started: upstream.timestamp_started,
    source_manifest: upstream.source_manifest,
    red_flag_detector_output: upstream.red_flag_detector_output,
    rfd_meta: upstream.rfd_meta,
    system_prompt: systemPrompt,
    user_message: JSON.stringify(userPayload, null, 2),
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: JSON.stringify(userPayload, null, 2) },
    ],
  },
};

// Parse Portfolio Fit Response — Phase 3 task 3.9
// Normalize the model output into the exact PortfolioFitOutput schema shape.

const response = $input.item.json;
const request = $('Build Portfolio Fit Request').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error('Portfolio Fit response missing message content.');
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Portfolio Fit JSON parse failed: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

const VALID_ALIGNMENT = ['HIGH', 'MEDIUM', 'LOW'];
const VALID_RECOMMENDATION = ['pass', 'pursue', 'advance_to_deep_diligence'];
const VALID_STRENGTH = ['HIGH', 'MEDIUM', 'LOW'];

function obj(v) { return v && typeof v === 'object' && !Array.isArray(v) ? v : {}; }
function str(v) { return typeof v === 'string' ? v : null; }
function num01(v) {
  if (typeof v !== 'number' || Number.isNaN(v)) return null;
  if (v < 0) return 0;
  if (v > 1) return 1;
  return v;
}

const pf = obj(parsed.portfolio_fit);

const strategicFit = obj(pf.strategic_fit);
const stageFit = obj(pf.stage_fit);

const synergyPotential = Array.isArray(pf.synergy_potential)
  ? pf.synergy_potential
      .map((x) => obj(x))
      .map((x) => ({
        portfolio_company: str(x.portfolio_company),
        synergy_type: str(x.synergy_type),
        description: str(x.description),
        strength: VALID_STRENGTH.includes(x.strength) ? x.strength : null,
      }))
      .filter((x) => x.portfolio_company && x.strength)
  : [];

const antiPatterns = Array.isArray(pf.anti_patterns)
  ? pf.anti_patterns
      .map((x) => obj(x))
      .map((x) => ({
        pattern: str(x.pattern),
        concern: str(x.concern),
      }))
      .filter((x) => x.pattern && x.concern)
  : [];

const portfolioFit = {
  strategic_fit: {
    score: num01(strategicFit.score),
    rationale: str(strategicFit.rationale) || '',
  },
  stage_fit: {
    score: num01(stageFit.score),
    rationale: str(stageFit.rationale) || '',
  },
  synergy_potential: synergyPotential,
  anti_patterns: antiPatterns,
  overall_thesis_alignment: VALID_ALIGNMENT.includes(pf.overall_thesis_alignment) ? pf.overall_thesis_alignment : null,
  recommended_action: VALID_RECOMMENDATION.includes(pf.recommended_action) ? pf.recommended_action : null,
};

return {
  json: {
    run_id: request.run_id,
    deal_id: request.deal_id,
    company_name: request.company_name,
    timestamp_started: request.timestamp_started,
    source_manifest: request.source_manifest,
    red_flag_detector_output: request.red_flag_detector_output,
    portfolio_fit_output: { portfolio_fit: portfolioFit },
    llm_usage: response.usage || {},
    llm_model: response.model || $env.ALICLOUD_MODEL,
  },
};
